"use client"
import { useEffect, useState } from "react"
import { db, isConfigured } from "../app/lib/firebase"
import { doc, onSnapshot, updateDoc } from "firebase/firestore"
import { Play, X, AlertCircle } from "lucide-react"

function extractVideoId(url: string): string | null {
  console.log("[v0] Extracting video ID from:", url)
  try {
    const u = new URL(url)

    // youtu.be/ID
    if (u.hostname.includes("youtu.be")) {
      const id = u.pathname.slice(1)
      console.log("[v0] Extracted from youtu.be:", id)
      return id
    }

    // youtube.com/watch?v=ID
    if (u.searchParams.get("v")) {
      const id = u.searchParams.get("v")
      console.log("[v0] Extracted from watch param:", id)
      return id
    }

    // youtube.com/embed/ID
    if (u.pathname.includes("/embed/")) {
      const id = u.pathname.split("/embed/")[1]
      console.log("[v0] Extracted from embed:", id)
      return id
    }
  } catch (error) {
    console.log("[v0] Error parsing URL:", error)
    return null
  }

  console.log("[v0] No video ID found")
  return null
}

export default function YouTubeWidget() {
  const [videos, setVideos] = useState<string[]>([])
  const [newVideo, setNewVideo] = useState("")

  useEffect(() => {
    if (!db || !isConfigured) {
      console.log("[v0] Firebase not configured")
      return
    }

    const unsub = onSnapshot(doc(db, "rooms/room1/widgets", "youtube"), (docSnap) => {
      const data = docSnap.data()
      if (data?.video) {
        setVideos(data.video)
      } else {
        setVideos([])
      }
    })
    return () => unsub()
  }, [])

  const addVideo = async () => {
    if (!newVideo.trim() || !db) return
    const id = extractVideoId(newVideo)
    if (!id) return
    try {
      await updateDoc(doc(db!, "rooms/room1/widgets", "youtube"), { video: [...videos, id] })
    } catch (error) {
      console.error("[v0] Error updating video:", error)
    }
    setNewVideo("")
  }

  const removeVideo = async (id: string) => {
    if (!db) return
    try {
      await updateDoc(doc(db!, "rooms/room1/widgets", "youtube"), { video: videos.filter((v) => v !== id) })
    } catch (error) {
      console.error("[v0] Error removing video:", error)
    }
  }

  if (!isConfigured) {
    return (
      <div className="space-y-4">
        <div className="flex items-start gap-3 p-4 bg-yellow-50 border border-yellow-200 rounded-xl">
          <AlertCircle className="w-5 h-5 text-yellow-600 flex-shrink-0 mt-0.5" />
          <div className="flex-1">
            <p className="text-sm font-medium text-yellow-800 mb-1">Firebase Not Configured</p>
            <p className="text-xs text-yellow-700">
              Please add your Firebase environment variables in the Vars section of the sidebar.
            </p>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-4">
      <div className="flex gap-2">
        <input
          type="text"
          value={newVideo}
          onChange={(e) => setNewVideo(e.target.value)}
          onKeyPress={(e) => e.key === "Enter" && addVideo()}
          placeholder="Paste YouTube URL..."
          className="flex-1 px-4 py-2.5 bg-input border border-border rounded-xl text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary transition-all"
        />
        <button
          onClick={addVideo}
          className="px-4 py-2.5 bg-primary text-primary-foreground rounded-xl hover:bg-primary/90 transition-colors flex-shrink-0"
        >
          <Play className="w-5 h-5" />
        </button>
      </div>

      {videos.length > 0 ? (
        <div className="space-y-3">
          {videos.map((videoId) => (
            <div key={videoId} className="relative">
              <div className="relative w-full pt-[56.25%] rounded-xl overflow-hidden bg-muted">
                <iframe
                  className="absolute top-0 left-0 w-full h-full"
                  src={`https://www.youtube.com/embed/${videoId}`}
                  allow="autoplay; encrypted-media"
                  allowFullScreen
                />
              </div>
              <button
                onClick={() => removeVideo(videoId)}
                className="absolute top-2 right-2 w-8 h-8 rounded-full bg-black/60 hover:bg-black/80 text-white flex items-center justify-center transition-colors backdrop-blur-sm"
                title="Remove video"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center py-8 text-muted-foreground text-sm">No videos added yet</div>
      )}
    </div>
  )
}
